const h = $input.item.json.headers || {};
const token = h['x-shopify-token'];
const store = h['x-shopify-store'];
if (!token || !store) {
  $execution.abort({ message: 'Missing Shopify credentials. Connect your store in Settings.' });
}
// Normalise store domain: strip protocol, ensure .myshopify.com
let domain = store.replace(/^https?:\/\//,'').replace(/\/.*$/,'');
if (!domain.includes('.myshopify.com') && !domain.includes('.')) {
  domain = `${domain}.myshopify.com`;
}
return [{ json: { token, domain } }];

const raw = $input.item.json.products || [];
const products = raw.map(p => {
  const price = p.variants?.[0]?.price || '0';
  const compareAt = p.variants?.[0]?.compare_at_price;
  const img = p.images?.[0]?.src || null;
  const stock = (p.variants || []).reduce((s,v) => s + (parseInt(v.inventory_quantity)||0), 0);
  return {
    id: p.id,
    title: p.title,
    handle: p.handle,
    status: p.status,
    product_type: p.product_type || '',
    tags: p.tags || '',
    price: parseFloat(price),
    compare_at_price: compareAt ? parseFloat(compareAt) : null,
    image: img,
    variant_count: (p.variants||[]).length,
    total_stock: stock,
    updated_at: p.updated_at
  };
});
return [{ json: { products, total: products.length } }];
